    const int32_t *dilation = attrs->GetAttrPointer<int32_t>(2);
    int32_t groups = attrs->GetAttrInt(3);

    uint32_t N = x_shape->GetOriginShape().GetDim(0);
    uint32_t inC = x_shape->GetOriginShape().GetDim(1) / groups;
    uint32_t D = x_shape->GetOriginShape().GetDim(2);
    uint32_t H = x_shape->GetOriginShape().GetDim(3);
    uint32_t W = x_shape->GetOriginShape().GetDim(4);

    uint32_t outC = w_shape->GetOriginShape().GetDim(0);
    uint32_t kD = w_shape->GetOriginShape().GetDim(2);
    uint32_t kH = w_shape->GetOriginShape().GetDim(3);
